// Define which RTD key this node is responsible for
const rtdKey = "RTD1"; // Change to RTD2, RTD3, RTD4 in other nodes

// Extract the value from the incoming message
const value = msg.payload.data[0];

// Store the value in the flow context
flow.set(rtdKey, value);

// Retrieve all current RTD values from context
const RTD1 = flow.get("RTD1");
const RTD2 = flow.get("RTD2");
const RTD3 = flow.get("RTD3");
const RTD4 = flow.get("RTD4");

// Check if all values are available
if (RTD1 !== undefined && RTD2 !== undefined && RTD3 !== undefined && RTD4 !== undefined) {
    // Create a new combined message
    return {
        payload: {
            RTD1: RTD1,
            RTD2: RTD2,
            RTD3: RTD3,
            RTD4: RTD4
        }
    };
}

